import java.util.*;

public class MapExample {
    public static void main(String[] args) {
        // HashMap — key-value pairs, no order
        System.out.println("=== HashMap ===");
        HashMap<String, Integer> scores = new HashMap<>();

        // Adding key-value pairs
        scores.put("Alice", 95);
        scores.put("Bob", 87);
        scores.put("Charlie", 92);
        scores.put("Alice", 98);  // Duplicate key — overwrites!

        System.out.println("Scores: " + scores);
        System.out.println("Size: " + scores.size());  // 3 (not 4)

        // TreeMap — sorted keys
        System.out.println("=== TreeMap ===");
        TreeMap<String, Integer> sortedScores = new TreeMap<>();
        sortedScores.put("Alice", 95);
        sortedScores.put("Bob", 87);
        sortedScores.put("Charlie", 92);
        sortedScores.put("Diana", 90);

        System.out.println("TreeMap: " + sortedScores);  // Sorted by key

        // Accessing values
        System.out.println("=== Accessing ===");
        System.out.println("Alice's score: " + scores.get("Alice"));
        System.out.println("Bob's score: " + scores.get("Bob"));
        System.out.println("Eve's score: " + scores.getOrDefault("Eve", 0));

        // Checking keys/values
        System.out.println("=== Checking ===");
        System.out.println("Contains key 'Alice'? " + scores.containsKey("Alice"));
        System.out.println("Contains key 'Eve'? " + scores.containsKey("Eve"));
        System.out.println("Contains value 95? " + scores.containsValue(95));
        System.out.println("Contains value 100? " + scores.containsValue(100));

        // Iterating over entries
        System.out.println("=== Iterating ===");
        System.out.println("Entry set:");
        for (Map.Entry<String, Integer> entry : scores.entrySet()) {
            System.out.println("  " + entry.getKey() + " = " + entry.getValue());
        }

        // Iterating over keys
        System.out.println("Keys: " + scores.keySet());
        System.out.println("Values: " + scores.values());

        // Removing entries
        System.out.println("=== Removing ===");
        scores.remove("Bob");
        System.out.println("After removing Bob: " + scores);

        // TreeMap specific operations
        System.out.println("=== TreeMap Operations ===");
        System.out.println("First key: " + sortedScores.firstKey());
        System.out.println("Last key: " + sortedScores.lastKey());
        System.out.println("Floor key (<= 'Charlie'): " + sortedScores.floorKey("Charlie"));
        System.out.println("Ceiling key (>= 'Charlie'): " + sortedScores.ceilingKey("Charlie"));

        // HashMap performance vs TreeMap
        System.out.println("=== Performance ===");
        System.out.println("HashMap: O(1) average for get/put");
        System.out.println("TreeMap: O(log n) for get/put");

        // HashMap with custom objects
        System.out.println("=== Custom Keys ===");
        HashMap<Person, String> personMap = new HashMap<>();
        personMap.put(new Person("Alice", 25), "Student");
        personMap.put(new Person("Bob", 30), "Teacher");
        System.out.println("Person map size: " + personMap.size());

        // Counting with HashMap
        System.out.println("=== Counting ===");
        String text = "apple banana apple orange banana apple";
        HashMap<String, Integer> wordCount = new HashMap<>();

        for (String word : text.split(" ")) {
            wordCount.put(word, wordCount.getOrDefault(word, 0) + 1);
        }
        System.out.println("Word counts: " + wordCount);
    }
}

class Person {
    String name;
    int age;

    Person(String name, int age) {
        this.name = name;
        this.age = age;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Person person = (Person) o;
        return age == person.age && Objects.equals(name, person.name);
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, age);
    }
}

