import java.util.*;

public class MapPractice {
    public static void main(String[] args) {
        HashMap<String, String> capitals = new HashMap<>();

        capitals.put("USA", "Washington D.C.");
        capitals.put("France", "Paris");
        capitals.put("Japan", "Tokyo");
        capitals.put("Brazil", "Brasília");

        System.out.println("Capitals: " + capitals);
        System.out.println("Capital of France: " + capitals.get("France"));
        System.out.println("Capital of Germany: " + capitals.getOrDefault("Germany", "Unknown"));

        capitals.remove("Brazil");
        System.out.println("After removing Brazil: " + capitals);
        System.out.println("Keys: " + capitals.keySet());
        System.out.println("Values: " + capitals.values());
        System.out.println("Contains 'USA'? " + capitals.containsKey("USA"));

        TreeMap<String, String> sorted = new TreeMap<>(capitals);
        System.out.println("Sorted: " + sorted);
    }
}
